#define N 5000

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[1] > y[1]) return -1;
    if (x[1] < y[1]) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) scanf("%d", &A[i]);
        for (int i = 0; i < N; i++) scanf("%d", &B[i]);
        int castles[N][2];
        for (int i = 0; i < N; i++) {
            castles[i][0] = A[i];
            castles[i][1] = B[i];
        }
        qsort(castles, N, sizeof(castles[0]), compare);
        long long ans[N];
        for (int K = 1; K <= N; K++) {
            long long max = 0;
            for (int i = 0; i <= N - K; i++) {
                long long sum = 0;
                for (int j = i; j < i + K; j++) {
                    sum += castles[j][0] + (j - i + 1) * castles[j][1];
                }
                if (sum > max) max = sum;
            }
            ans[K - 1] = max;
        }
        for (int i = 0; i < N; i++) printf("%lld ", ans[i]);
        printf("\n");
    }
    return 0;
}

