using namespace std;

const int N = 5000;

bool compare(pair<int, int> a, pair<int, int> b) {
    return a.second > b.second;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<int> A(n), B(n);
        for (int i = 0; i < n; i++) cin >> A[i];
        for (int i = 0; i < n; i++) cin >> B[i];
        vector<pair<int, int>> castles;
        for (int i = 0; i < n; i++) {
            castles.push_back({A[i], B[i]});
        }
        sort(castles.begin(), castles.end(), compare);
        long long ans[n];
        for (int K = 1; K <= n; K++) {
            long long max = 0;
            for (int i = 0; i <= n - K; i++) {
                long long sum = 0;
                for (int j = i; j < i + K; j++) {
                    sum += castles[j].first + (j - i + 1) * castles[j].second;
                }
                if (sum > max) max = sum;
            }
            ans[K - 1] = max;
        }
        for (int i = 0; i < n; i++) cout << ans[i] << " ";
        cout << endl;
    }
    return 0;
}

