import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Castle implements Comparable<Castle> {
        int a, b;
        Castle(int a, int b) {
            this.a = a;
            this.b = b;
        }
        @Override
        public int compareTo(Castle o) {
            return Integer.compare(o.b, this.b);
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Castle[] castles = new Castle[N];
            for (int i = 0; i < N; i++) {
                int a = sc.nextInt();
                castles[i] = new Castle(a, 0);
            }
            for (int i = 0; i < N; i++) {
                int b = sc.nextInt();
                castles[i].b = b;
            }
            Arrays.sort(castles);
            long[] ans = new long[N];
            for (int K = 1; K <= N; K++) {
                long max = 0;
                for (int i = 0; i <= N - K; i++) {
                    long sum = 0;
                    for (int j = i; j < i + K; j++) {
                        sum += castles[j].a + (j - i + 1) * castles[j].b;
                    }
                    if (sum > max) max = sum;
                }
                ans[K - 1] = max;
            }
            for (int i = 0; i < N; i++) System.out.print(ans[i] + " ");
            System.out.println();
        }
    }
}

