const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const B = readline().split(' ').map(x => parseInt(x));
    const castles = A.map((a, i) => [a, B[i]]).sort((a, b) => b[1] - a[1]);
    const ans = new Array(N).fill(0);
    for (let K = 1; K <= N; K++) {
        let maxSum = 0;
        for (let j = 0; j <= N - K; j++) {
            let sum = 0;
            for (let k = j; k < j + K; k++) {
                sum += castles[k][0] + (k - j + 1) * castles[k][1];
            }
            maxSum = Math.max(maxSum, sum);
        }
        ans[K - 1] = maxSum;
    }
    console.log(ans.join(' '));
}
